<?php require __DIR__.'/bootstrap.php'; $type=$_GET['type'] ?? ''; if($_SERVER['REQUEST_METHOD']==='GET') out(get_payload($type)); require_admin(); $body=read_json_body(); if($_SERVER['REQUEST_METHOD']==='PUT' && isset($body['payload'])){ save_payload($type,$body['payload']); out(['ok'=>true]); } $data=get_payload($type); if($type==='settings'){ $payload=$body['payload'] ?? $body; save_payload($type,$payload); out(['ok'=>true,'payload'=>$payload]); } if(!isset($data['items']) || !is_array($data['items'])) $data=['items'=>[]]; if($_SERVER['REQUEST_METHOD']==='POST'){ $item=$body['item'] ?? $body; if(empty($item['slug']) && empty($item['id'])) $item['id']='item-'.time(); array_unshift($data['items'],$item); } elseif($_SERVER['REQUEST_METHOD']==='PATCH' || $_SERVER['REQUEST_METHOD']==='PUT'){ $key=$body['key'] ?? $body['slug'] ?? $body['id'] ?? ''; $item=$body['item'] ?? $body; foreach($data['items'] as &$x){ if(item_key($x)===$key){ $x=array_merge($x,$item); break; } } } elseif($_SERVER['REQUEST_METHOD']==='DELETE'){ $key=$body['key'] ?? $body['slug'] ?? $body['id'] ?? ''; $data['items']=array_values(array_filter($data['items'], fn($x)=>item_key($x)!==$key)); } else { out(['ok'=>false,'error'=>'Method not allowed'],405); } save_payload($type,$data); out(['ok'=>true,'data'=>$data]);
